import { NextResponse, type NextRequest } from 'next/server'

const GOOGLE_CLIENT_ID = process.env.GOOGLE_CLIENT_ID!
const GOOGLE_REDIRECT_URI = process.env.GOOGLE_REDIRECT_URI!

// Scopes: read-only access to Google Photos library
const SCOPES = [
    'https://www.googleapis.com/auth/photoslibrary.readonly',
    'openid',
    'email',
].join(' ')

export async function GET(request: NextRequest) {
    const params = new URLSearchParams({
        client_id: GOOGLE_CLIENT_ID,
        redirect_uri: GOOGLE_REDIRECT_URI,
        response_type: 'code',
        scope: SCOPES,
        access_type: 'offline',  // get refresh_token
        prompt: 'consent',       // force consent to always get refresh_token
    })

    const authUrl = `https://accounts.google.com/o/oauth2/v2/auth?${params.toString()}`

    return NextResponse.redirect(authUrl)
}

import { createClient } from '@/utils/supabase/server'
import { redirect } from 'next/navigation'
import { getActiveFamily } from '@/utils/active-family'
import { FamilyList } from './FamilyList'

export default async function FamiliesPage() {
    const supabase = await createClient()

    const { data: { user } } = await supabase.auth.getUser()
    if (!user) redirect('/login')

    // Fetch memberships with their family names and roles
    const { data: memberships, error: memError } = await supabase
        .from('members')
        .select(`
            family_id,
            role,
            joined_at,
            families (
                id,
                name
            )
        `)
        .eq('profile_id', user.id)
        .order('joined_at', { ascending: true })

    if (memError || !memberships) {
        console.error('Error fetching memberships:', memError)
        return <div className="p-8 text-red-600">Failed to load families.</div>
    }

    // Now, for each family, fetch the member count and a few members for preview
    const familiesWithDetails = await Promise.all(
        memberships.map(async (m) => {
            const familyId = m.family_id

            // Get member count
            const { count, error: countError } = await supabase
                .from('members')
                .select('*', { count: 'exact', head: true })
                .eq('family_id', familyId)

            // Get a few members for a simple hierarchy preview
            // We'll just grab the first 5 joined members to keep it "mini"
            const { data: previewMembers } = await supabase
                .from('members')
                .select('id, profile_id, role, profiles(full_name)')
                .eq('family_id', familyId)
                .order('joined_at', { ascending: true })
                .limit(5)

            return {
                familyId: m.family_id,
                familyName: (m.families as any)?.name ?? 'Unnamed Family',
                role: m.role,
                memberCount: count ?? 0,
                previewMembers: (previewMembers ?? []).map(pm => ({
                    id: pm.id,
                    name: (pm.profiles as any)?.full_name ?? 'Unknown',
                    role: pm.role
                }))
            }
        })
    )

    // Get the current active family ID for highlighting
    const { data: profile } = await supabase
        .from('profiles')
        .select('active_family_id')
        .eq('id', user.id)
        .single()

    return (
        <div className="min-h-screen bg-gray-50 p-8">
            <div className="max-w-4xl mx-auto">
                <header className="mb-10">
                    <h1 className="text-3xl font-bold text-gray-900">Minha Conta</h1>
                    <p className="text-gray-500 mt-1">Gerencie suas fam├¡lias e conex├Áes no RootLine.</p>
                </header>

                <div className="space-y-6">
                    <h2 className="text-xl font-semibold text-gray-800">Minhas Fam├¡lias</h2>
                    <FamilyList
                        families={familiesWithDetails}
                        activeFamilyId={profile?.active_family_id ?? ''}
                    />
                </div>
            </div>
        </div>
    )
}

import { createFamily } from './actions'
import { createClient } from '@/utils/supabase/server'
import { redirect } from 'next/navigation'

export default async function OnboardingPage({
    searchParams,
}: {
    searchParams: { message: string }
}) {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) {
        redirect('/login')
    }

    // Check if they already have an active family
    const { data: members } = await supabase
        .from('members')
        .select('family_id')
        .eq('profile_id', user.id)
        .limit(1)

    // If already part of a family, MVP rule defaults them and skips onboarding
    if (members && members.length > 0) {
        redirect('/timeline')
    }

    return (
        <div className="flex justify-center items-center min-h-screen bg-gray-50 p-4">
            <div className="animate-in flex flex-col w-full max-w-md p-8 bg-white rounded-lg shadow-md border border-gray-100">
                <div className="text-center mb-6">
                    <h1 className="text-3xl font-semibold tracking-tight text-gray-900">Welcome to RootLine</h1>
                    <p className="text-sm text-gray-500 mt-2">Let's create your first Living Archive.</p>
                </div>

                <form action={createFamily} className="flex flex-col gap-4">
                    <div>
                        <label className="text-sm font-medium text-gray-700 block mb-1" htmlFor="familyName">
                            Family Name
                        </label>
                        <input
                            className="w-full rounded-md px-4 py-2 border border-gray-300 focus:ring-2 focus:ring-blue-500 focus:outline-none"
                            name="familyName"
                            placeholder="e.g. The Silva Family"
                            required
                        />
                    </div>

                    <button
                        type="submit"
                        className="w-full bg-blue-600 hover:bg-blue-700 text-white rounded-md px-4 py-3 transition-colors font-medium mt-4 shadow-sm"
                    >
                        Create Family Archive
                    </button>

                    {searchParams?.message && (
                        <p className="mt-4 p-4 bg-red-50 text-red-900 border border-red-200 text-center text-sm rounded-md">
                            {searchParams.message}
                        </p>
                    )}
                </form>

                <div className="mt-6 border-t pt-4 text-center">
                    <p className="text-sm text-gray-500 mb-2">Were you invited by someone?</p>
                    <p className="text-xs text-gray-400">Please check your email and click the invitation link to join an existing family.</p>
                </div>
            </div>
        </div>
    )
}

'use client'

import { useCallback, useEffect, useRef, useState } from 'react'
import { getPhotoViewUrl } from './view-url'

type LightboxPhoto = {
    id: string
    thumbUrl: string
    originalFilename: string | null
    takenAt: string | null
}

type LightboxProps = {
    photos: LightboxPhoto[]
    initialIndex: number
    onClose: () => void
}

export function Lightbox({ photos, initialIndex, onClose }: LightboxProps) {
    const [index, setIndex] = useState(initialIndex)
    const [fullUrl, setFullUrl] = useState<string | null>(null)
    const [fullLoaded, setFullLoaded] = useState(false)
    const [error, setError] = useState<string | null>(null)
    const containerRef = useRef<HTMLDivElement>(null)

    const photo = photos[index]

    // Fetch the full-res signed URL whenever the photo changes
    useEffect(() => {
        setFullUrl(null)
        setFullLoaded(false)
        setError(null)

        getPhotoViewUrl(photo.id, 'full').then((result) => {
            if ('error' in result) {
                setError(result.error)
            } else {
                setFullUrl(result.url)
            }
        })
    }, [photo.id])

    const goNext = useCallback(() => {
        setIndex((i) => (i + 1) % photos.length)
    }, [photos.length])

    const goPrev = useCallback(() => {
        setIndex((i) => (i - 1 + photos.length) % photos.length)
    }, [photos.length])

    // Keyboard navigation
    useEffect(() => {
        function onKey(e: KeyboardEvent) {
            if (e.key === 'Escape') onClose()
            if (e.key === 'ArrowRight') goNext()
            if (e.key === 'ArrowLeft') goPrev()
        }
        window.addEventListener('keydown', onKey)
        return () => window.removeEventListener('keydown', onKey)
    }, [onClose, goNext, goPrev])

    // Trap focus & prevent body scroll
    useEffect(() => {
        document.body.style.overflow = 'hidden'
        containerRef.current?.focus()
        return () => { document.body.style.overflow = '' }
    }, [])

    return (
        <div
            ref={containerRef}
            tabIndex={-1}
            role="dialog"
            aria-modal="true"
            aria-label="Photo lightbox"
            className="fixed inset-0 z-50 bg-black/90 flex items-center justify-center outline-none"
            onClick={(e) => { if (e.target === e.currentTarget) onClose() }}
        >
            {/* Close button */}
            <button
                onClick={onClose}
                className="absolute top-4 right-4 text-white/70 hover:text-white text-3xl leading-none z-10"
                aria-label="Close lightbox"
            >
                ├ù
            </button>

            {/* Prev / Next */}
            {photos.length > 1 && (
                <>
                    <button
                        onClick={goPrev}
                        className="absolute left-4 top-1/2 -translate-y-1/2 text-white/70 hover:text-white text-4xl z-10 px-3"
                        aria-label="Previous photo"
                    >
                        ÔÇ╣
                    </button>
                    <button
                        onClick={goNext}
                        className="absolute right-4 top-1/2 -translate-y-1/2 text-white/70 hover:text-white text-4xl z-10 px-3"
                        aria-label="Next photo"
                    >
                        ÔÇ║
                    </button>
                </>
            )}

            {/* Image container */}
            <div className="relative max-h-[90vh] max-w-[90vw] flex items-center justify-center">
                {/* Thumb placeholder (always rendered while full loads) */}
                {/* eslint-disable-next-line @next/next/no-img-element */}
                <img
                    src={photo.thumbUrl}
                    alt={photo.originalFilename ?? 'Family photo'}
                    className={`max-h-[90vh] max-w-[90vw] object-contain rounded transition-opacity duration-300 ${fullLoaded ? 'opacity-0 absolute inset-0 w-full h-full' : 'opacity-100 blur-sm scale-[0.99]'
                        }`}
                    aria-hidden={fullLoaded}
                />

                {/* Full-res image: mounts hidden, reveals when loaded */}
                {fullUrl && !error && (
                    // eslint-disable-next-line @next/next/no-img-element
                    <img
                        src={fullUrl}
                        alt={photo.originalFilename ?? 'Family photo'}
                        className={`max-h-[90vh] max-w-[90vw] object-contain rounded transition-opacity duration-500 ${fullLoaded ? 'opacity-100' : 'opacity-0'
                            }`}
                        onLoad={() => setFullLoaded(true)}
                        onError={() => setError('Full resolution could not be loaded.')}
                    />
                )}

                {/* Loading indicator while full-res is fetching */}
                {!fullUrl && !error && (
                    <div className="absolute inset-0 flex items-center justify-center">
                        <div className="w-8 h-8 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    </div>
                )}

                {/* Error state */}
                {error && (
                    <div className="absolute inset-0 flex items-center justify-center bg-black/60 rounded">
                        <div className="text-center text-white/80 p-4">
                            <p className="text-2xl mb-2">ÔÜá´©Å</p>
                            <p className="text-sm">{error}</p>
                            <p className="text-xs text-white/50 mt-1">Try refreshing the page.</p>
                        </div>
                    </div>
                )}
            </div>

            {/* Caption bar */}
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-center text-white/60 text-xs space-y-0.5 pointer-events-none">
                {photo.originalFilename && <p>{photo.originalFilename}</p>}
                {photo.takenAt && <p>{new Date(photo.takenAt).toLocaleDateString()}</p>}
                <p>{index + 1} / {photos.length}</p>
            </div>
        </div>
    )
}

'use server'

import { createClient } from '@/utils/supabase/server'
import { revalidatePath } from 'next/cache'
import { redirect } from 'next/navigation'
import { getActiveFamily } from '@/utils/active-family'

// Max 10MB per file
const MAX_FILE_SIZE = 10 * 1024 * 1024

export async function uploadPhoto(formData: FormData) {
    const supabase = await createClient()

    const { data: { user } } = await supabase.auth.getUser()
    if (!user) {
        return { error: 'Not authenticated' }
    }

    // Find active family + verify contributor/admin role
    const { familyId, role } = await getActiveFamily(supabase)

    if (!['admin', 'contributor'].includes(role)) {
        return { error: 'You do not have permission to upload photos' }
    }

    const file = formData.get('photo') as File | null
    const takenAt = formData.get('taken_at') as string | null

    if (!file || file.size === 0) {
        return { error: 'No file provided' }
    }

    if (!['image/jpeg', 'image/jpg', 'image/png', 'image/webp', 'image/heic'].includes(file.type)) {
        return { error: 'Only JPEG, PNG, WebP and HEIC images are supported' }
    }

    if (file.size > MAX_FILE_SIZE) {
        return { error: 'File must be smaller than 10 MB' }
    }

    const fileExt = file.name.split('.').pop()?.toLowerCase() ?? 'jpg'
    const photoId = crypto.randomUUID()
    // Standard: families/<family_id>/full/<uuid>.<ext>
    // Thumbnail will be families/<family_id>/thumbs/<uuid>.<ext> (generated server-side in future)
    const storagePath = `families/${familyId}/full/${photoId}.${fileExt}`

    // Upload to Supabase Storage bucket 'family-photos'
    const { error: uploadError } = await supabase.storage
        .from('family-photos')
        .upload(storagePath, file, {
            cacheControl: '3600',
            upsert: false,
            contentType: file.type
        })

    if (uploadError) {
        console.error('Storage upload error:', uploadError)
        return { error: 'Failed to upload photo. Please try again.' }
    }

    // Insert photo record
    const { error: insertError } = await supabase
        .from('photos')
        .insert({
            id: photoId,
            family_id: familyId,
            uploaded_by: user.id,
            storage_path: storagePath,
            original_filename: file.name,
            size_bytes: file.size,
            mime_type: file.type,
            taken_at: takenAt || null,
            source: 'manual'
        })

    if (insertError) {
        console.error('DB insert error:', insertError)
        // Clean up orphaned storage object
        await supabase.storage.from('family-photos').remove([storagePath])
        return { error: 'Failed to save photo record.' }
    }

    revalidatePath('/timeline')
    revalidatePath('/photos')

    return { success: true, photoId }
}

'use server'

import { createClient } from '@/utils/supabase/server'
import { randomBytes, createHash } from 'crypto'
import { revalidatePath } from 'next/cache'
import { getActiveFamily } from '@/utils/active-family'

export async function sendInvite(formData: FormData) {
    const supabase = await createClient()

    const { data: { user } } = await supabase.auth.getUser()
    if (!user) {
        return { error: 'Not authenticated' }
    }

    const email = formData.get('email') as string
    const targetRole = formData.get('role') as string || 'contributor'

    if (!email) {
        return { error: 'Email is required' }
    }

    // 1. Get Active Family and verify Admin status
    const { familyId, role } = await getActiveFamily(supabase)

    if (role !== 'admin') {
        return { error: 'You are not an admin of the active family' }
    }

    // 2. Simple Rate Limit: Max 10 invites per day per admin (Timezone UTC)
    const { count } = await supabase
        .from('invites')
        .select('*', { count: 'exact', head: true })
        .eq('invited_by', user.id)
        .gte('created_at', new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString())

    if (count && count >= 10) {
        return { error: 'Rate limit exceeded: You can only send 10 invitations per 24 hours.' }
    }

    // 3. Generate Token and Hash
    const rawToken = randomBytes(32).toString('hex')
    const tokenHash = createHash('sha256').update(rawToken).digest('hex')

    // 4. Insert into invites table
    const { error: inviteError, data: invite } = await supabase
        .from('invites')
        .insert({
            family_id: familyId,
            invited_by: user.id,
            invited_email: email,
            role: role,
            token_hash: tokenHash,
            status: 'pending'
        })
        .select('id')
        .single()

    if (inviteError) {
        console.error('Invite generation error:', inviteError)
        // Avoid leaking unique violation (reuse of email pending) unless explicitly needed
        return { error: 'Failed to create invitation. They might already be invited.' }
    }

    revalidatePath('/timeline')

    // In production, an external worker or Edge Function triggers via Database Webhook
    // sending the email using Resend:
    // url: `https://app.rootline.com/invite?token=${rawToken}`
    // For the MVP testing and Walkthrough, we will return the generated plain token snippet
    // so the user can copy-paste it for Task 2.3 validation locally.
    const inviteLink = `http://localhost:3000/invite/${rawToken}`

    return {
        success: true,
        inviteLink: inviteLink,
        message: `Invite generated! In production, a background worker emails this to ${email}.`
    }
}

import { createClient } from '@/utils/supabase/server'
import { redirect } from 'next/navigation'
import { FamilyTree } from './FamilyTree'
import { getActiveFamily } from '@/utils/active-family'
import { FamilySwitcher } from '@/components/FamilySwitcher'



const MAX_MEMBERS = 25

export default async function TreePage() {
    const supabase = await createClient()

    const { data: { user } } = await supabase.auth.getUser()
    if (!user) redirect('/login')

    // Use centralized active family resolver
    const { familyId, familyName, role, allFamilies } = await getActiveFamily(supabase)

    if (!familyId) redirect('/onboarding') // Changed from !membership to !familyId

    // familyName already resolved by getActiveFamily, familyId is also resolved.
    // The following lines are now redundant:
    // const familyId = membership.family_id
    // const familyName = (membership.families as any)?.name ?? 'Your Family'

    // Fetch all members + their profiles
    const { data: members, error: membersError } = await supabase
        .from('members')
        .select('id, profile_id, role, joined_at, profiles(full_name)')
        .eq('family_id', familyId)
        .order('joined_at', { ascending: true })

    if (membersError) {
        return (
            <ErrorState message="Failed to load family members. Please try again." />
        )
    }

    const memberCount = members?.length ?? 0

    // Fetch relationships
    const { data: relationships, error: relError } = await supabase
        .from('relationships')
        .select('id, member_a_id, member_b_id, type')
        .eq('family_id', familyId)

    if (relError) {
        return <ErrorState message="Failed to load relationships." />
    }

    const hasRelationships = relationships && relationships.length > 0
    const isOverCap = memberCount > MAX_MEMBERS

    return (
        <div className="min-h-screen bg-gray-50 p-6">
            <div className="max-w-6xl mx-auto">
                {/* Header */}
                <div className="flex items-center justify-between mb-6">
                    <div>
                        <h1 className="text-2xl font-bold text-gray-900">{familyName} ÔÇö Family Tree</h1>
                        <FamilySwitcher activeFamilyId={familyId} families={allFamilies} />
                        <p className="text-sm text-gray-500 mt-0.5">
                            {memberCount} member{memberCount !== 1 ? 's' : ''} in this archive
                        </p>
                    </div>
                    <div className="flex items-center gap-4">
                        <a href="/families" className="text-sm font-medium text-gray-400 hover:text-indigo-600 transition-colors">
                            Minha Conta
                        </a>
                        <a
                            href="/timeline"
                            className="text-sm text-blue-600 hover:underline"
                        >
                            ÔåÉ Back to Timeline
                        </a>
                    </div>
                </div>

                {/* Cap warning */}
                {isOverCap && (
                    <div className="mb-4 p-4 bg-amber-50 border border-amber-200 rounded-lg text-amber-800 text-sm">
                        ÔÜá´©Å This family has {memberCount} members. The MVP tree visualization
                        is capped at {MAX_MEMBERS}. Only the first {MAX_MEMBERS} members are shown.
                        Full display is available in P0-B.
                    </div>
                )}

                {/* Empty state */}
                {members && members.length === 0 ? (
                    <EmptyState />
                ) : !hasRelationships ? (
                    <div className="flex flex-col items-center justify-center h-[400px] bg-white rounded-xl border border-gray-200 border-dashed">
                        <p className="text-4xl mb-3">­ƒî▒</p>
                        <p className="text-gray-700 font-medium">No relationships defined yet</p>
                        <p className="text-sm text-gray-400 mt-1">
                            Members are loaded ÔÇö add relationships to build the tree.
                        </p>
                    </div>
                ) : (
                    <FamilyTree
                        members={(isOverCap ? members!.slice(0, MAX_MEMBERS) : members!) as any}
                        relationships={relationships!}
                    />
                )}

                {/* Legend */}
                {hasRelationships && (
                    <div className="mt-4 flex gap-6 text-xs text-gray-500">
                        <span className="flex items-center gap-1.5">
                            <span className="inline-block w-4 h-0.5 bg-indigo-500" /> Parent ÔåÆ Child
                        </span>
                        <span className="flex items-center gap-1.5">
                            <span className="inline-block w-4 h-0.5 bg-pink-500" style={{ borderTop: '2px dashed' }} /> Spouse
                        </span>
                        <span className="text-gray-400">Click a node for details</span>
                    </div>
                )}
            </div>
        </div>
    )
}

